package renderer

import (
	"github.com/kunorikiku/yet-another-overlay-generator/internal/model"
)

// InstallScriptConfig 安装脚本渲染数据
type InstallScriptConfig struct {
	NodeName     string
	NodeRole     string
	Platform     string
	OverlayIP    string
	HasBabel     bool
	HasForward   bool
	WgConfName   string
	BabelConfName string
	SysctlConfName string
}

const installScriptTemplate = `#!/usr/bin/env bash
# Install script for node: {{ .NodeName }}
# Generated by Overlay Network Config Orchestrator
# Platform: {{ .Platform }}
# Role: {{ .NodeRole }}

set -euo pipefail

# ============================================================
# Phase 1: Environment Preparation
# ============================================================

echo "=== Phase 1: Environment Preparation ==="

# Check root
if [ "$(id -u)" -ne 0 ]; then
    echo "ERROR: This script must be run as root" >&2
    exit 1
fi

# Detect OS
if [ -f /etc/os-release ]; then
    . /etc/os-release
    OS_ID="$ID"
    OS_VERSION="$VERSION_ID"
    echo "Detected OS: $OS_ID $OS_VERSION"
else
    echo "ERROR: Cannot detect OS (no /etc/os-release)" >&2
    exit 1
fi

# Verify supported platform
case "$OS_ID" in
    debian|ubuntu)
        echo "Supported platform: $OS_ID"
        ;;
    *)
        echo "WARNING: Unsupported platform: $OS_ID (targeting Debian/Ubuntu)" >&2
        ;;
esac

# Install dependencies
echo "Installing dependencies..."
apt-get update -qq
apt-get install -y -qq wireguard wireguard-tools
{{ if .HasBabel -}}
apt-get install -y -qq babeld
{{ end -}}

# Create directories
mkdir -p /etc/wireguard
{{ if .HasBabel -}}
mkdir -p /etc/babel
{{ end -}}

echo "Phase 1 complete."

# ============================================================
# Phase 2: Deploy Configuration
# ============================================================

echo "=== Phase 2: Deploy Configuration ==="

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"

# Deploy WireGuard configuration
echo "Deploying WireGuard configuration..."
if [ -f "/etc/wireguard/{{ .WgConfName }}" ]; then
    cp "/etc/wireguard/{{ .WgConfName }}" "/etc/wireguard/{{ .WgConfName }}.bak.$(date +%s)"
    echo "  Backed up existing WireGuard config"
fi
cp "$SCRIPT_DIR/wireguard/{{ .WgConfName }}" /etc/wireguard/{{ .WgConfName }}
chmod 600 /etc/wireguard/{{ .WgConfName }}
echo "  WireGuard config deployed: /etc/wireguard/{{ .WgConfName }}"

{{ if .HasBabel -}}
# Deploy Babel configuration
echo "Deploying Babel configuration..."
if [ -f "/etc/babel/{{ .BabelConfName }}" ]; then
    cp "/etc/babel/{{ .BabelConfName }}" "/etc/babel/{{ .BabelConfName }}.bak.$(date +%s)"
    echo "  Backed up existing Babel config"
fi
cp "$SCRIPT_DIR/babel/{{ .BabelConfName }}" /etc/babel/{{ .BabelConfName }}
echo "  Babel config deployed: /etc/babel/{{ .BabelConfName }}"
{{ end -}}

# Deploy sysctl configuration
echo "Deploying sysctl configuration..."
cp "$SCRIPT_DIR/sysctl/{{ .SysctlConfName }}" /etc/sysctl.d/{{ .SysctlConfName }}
echo "  Sysctl config deployed: /etc/sysctl.d/{{ .SysctlConfName }}"

echo "Phase 2 complete."

# ============================================================
# Phase 3: Activate and Verify
# ============================================================

echo "=== Phase 3: Activate and Verify ==="

# Apply sysctl
echo "Applying sysctl settings..."
sysctl --system > /dev/null 2>&1
{{ if .HasForward -}}
echo "  IPv4 forwarding: $(cat /proc/sys/net/ipv4/ip_forward)"
{{ end -}}

# Start WireGuard
WG_IFACE="{{ .WgConfName }}"
WG_IFACE="${WG_IFACE%.conf}"
echo "Starting WireGuard interface: $WG_IFACE..."
if wg show "$WG_IFACE" > /dev/null 2>&1; then
    echo "  Interface $WG_IFACE already up, restarting..."
    wg-quick down "$WG_IFACE" || true
fi
wg-quick up "$WG_IFACE"
echo "  WireGuard interface $WG_IFACE is up"

# Enable WireGuard on boot
systemctl enable wg-quick@"$WG_IFACE" 2>/dev/null || true

{{ if .HasBabel -}}
# Start Babel
echo "Starting Babel..."
systemctl restart babeld
systemctl enable babeld
echo "  Babel daemon started"
{{ end -}}

# Show status
echo ""
echo "============================================================"
echo "  Node: {{ .NodeName }}"
echo "  Overlay IP: {{ .OverlayIP }}"
echo "  Role: {{ .NodeRole }}"
echo "============================================================"
echo ""
echo "WireGuard status:"
wg show "$WG_IFACE"
echo ""
{{ if .HasBabel -}}
echo "Babel status:"
echo "  Check with: babeld -d 1"
echo ""
{{ end -}}
echo "Installation complete!"
echo "Note: If peers are not yet online, connections will establish once they come up."
`

// RenderInstallScript 渲染单个节点的安装脚本
func RenderInstallScript(node *model.Node, hasBabel bool) (string, error) {
	config := InstallScriptConfig{
		NodeName:       node.Name,
		NodeRole:       node.Role,
		Platform:       node.Platform,
		OverlayIP:      node.OverlayIP,
		HasBabel:       hasBabel,
		HasForward:     node.Capabilities.CanForward,
		WgConfName:     "wg0.conf",
		BabelConfName:  "babeld.conf",
		SysctlConfName: "99-overlay.conf",
	}

	if config.Platform == "" {
		config.Platform = "debian"
	}

	return renderTemplate("install.sh", installScriptTemplate, config)
}
